/**
 * Data assembly for the photographer pages ("Darkroom" design).
 *
 * Reads live rows from D1 when available and enriches them with true image
 * dimensions from lib/data/photoManifest.json (generated by
 * scripts/build-photo-manifest.mjs — EXIF-orientation corrected, plus
 * white-matte detection for the squares wall).
 *
 * When D1 is not reachable (local `next dev`, build machines) the manifest
 * itself is used as the row source, so pages always render with real content.
 */

import manifest from './photoManifest.json'
import { normalizePhotoKey, toPublicPath } from '../photoUtils'

const CAT_ZH = {
  HK: '香港',
  City: '城市',
  Travel: '旅途',
  Portrait: '人像',
  Emotion: '情绪',
  Lover: '恋人',
  Wedding: '婚礼',
  Nature: '自然',
  Ghibli: '吉卜力',
  Phone: '随手',
}

const CAT_JA = {
  HK: '香港',
  City: '街',
  Travel: '旅',
  Portrait: 'ポートレート',
  Emotion: '感情',
  Lover: '恋人',
  Wedding: 'ウェディング',
  Nature: '自然',
  Ghibli: 'ジブリ',
  Phone: 'スナップ',
}

// INDEX overlay order — people first (portraits are the main business).
const CAT_ORDER = ['Portrait', 'Emotion', 'Lover', 'Wedding', 'HK', 'City', 'Travel', 'Nature', 'Ghibli', 'Phone']

// Hand-picked hero images — the photographer's own banner curation (1–5).
// Shown as one full-bleed band; `fw` is the flex weight (≈ visible aspect
// ratio) so portraits stay nearly uncropped while the landscape frame (4)
// takes a center crop and the biggest parallax travel.
const HERO_PANELS = [
  { p: '/photography/banner/2.jpg', w: 1344, h: 1680, fw: 0.8 },
  { p: '/photography/banner/1.jpg', w: 1343, h: 1680, fw: 0.8 },
  { p: '/photography/banner/3.jpg', w: 1344, h: 1680, fw: 0.8 },
  { p: '/photography/banner/5.jpg', w: 1344, h: 1680, fw: 0.8 },
  { p: '/photography/banner/4.jpg', w: 1640, h: 1093, fw: 0.95 },
]

/**
 * CH.01 PEOPLE rides the dedicated Portrait index and nothing else — no
 * Emotion / Lover / Wedding frames mixed in. Named frames were curated by eye
 * and are resolved by filename so upstream re-sorting can't break them; each
 * row is then topped up to PEOPLE_ROW_LEN from the head of the Portrait pool,
 * skipping every name curated below (and every white matte, which belongs to
 * the wall) so no frame shows up twice across the three rows.
 */
const PEOPLE_ROW_LEN = [7, 10, 9]

const STRIP_A_PICKS = [
  ['Portrait', 'DSC00641.webp'],                              // chin on hand, smiling
  ['Portrait', 'DSC00656.webp'],                              // through the glass reflection
]

const STRIP_B_PICKS = [
  ['Portrait', '0B712FEC-DBF8-4D04-B97B-2D7C458F5529.webp'],  // couple in the snow
  ['Portrait', 'DSC03330.webp'],                              // looking up, braided hair, backlit
  ['Portrait', 'DSC03758.webp'],                              // girl with the bouquet
  ['Portrait', 'D22B9E2C-FA2E-4728-9EA2-137F0AA88C7F.webp'],  // smiles across the table
]

const STRIP_C_PICKS = [
  ['Portrait', '0E6305BE-35AD-4370-B512-BEE2AE5827D4.webp'],  // writing by the rain window
  ['Portrait', 'DSC02133.webp'],                              // backlit under the trees
  ['Portrait', 'DSC03397.webp'],                              // card held over the face
  ['Portrait', 'DSC03486.webp'],                               // drinking, dappled light
  ['Portrait', 'DSCF2799.webp'],                               // close profile
  ['Portrait', 'DSCF2904.webp'],                               // smelling the flowers
  ['Portrait', 'DSCF3124.webp'],                               // arms raised, joy
  ['Portrait', 'DSCF3195.webp'],                               // looking back over the shoulder
  ['Portrait', 'EBB19E69-C9C2-420E-BAB8-5CF2620F3A9D.webp'],  // sunlit profile
]

const PEOPLE_CURATED = new Set(
  [...STRIP_A_PICKS, ...STRIP_B_PICKS, ...STRIP_C_PICKS].map(([, filename]) => filename)
)

/**
 * Three drifting city layers. HK sort_order is a trip album — the genuine
 * street frames were picked by eye (arrival snapshots live in s0–35).
 */
const CITY_ROW_PICKS = [
  [
    ['City', 'E269F072-B91F-4AB0-9EBA-6B0600E08FBD.jpg'],     // dusk street, headlights
    ['HK', '20250831_121750.webp'],                           // road curve, red car
    ['HK', '20250831_091035.webp'],                           // dense apartment blocks
    ['HK', '20250829_171642.webp'],                           // crossing at golden hour
    ['City', 'DB815819-870B-4D96-8E0F-412B5429F302.webp'],    // night city under the wing
    ['HK', '20250830_144603.webp'],                           // harbour promenade
    ['HK', '20250829_202406.webp'],                           // harbour neon, night
  ],
  [
    ['City', 'IMG_0278.jpeg'],                                // b&w frieze panorama
    ['HK', '20250831_110334.webp'],                           // taxi under the overpass
    ['HK', '20250831_123352.webp'],                           // colonial block, towers
    ['HK', '20250829_172528.webp'],                           // street crowd, signs
    ['City', '517D14E0-CFB9-4337-BBAA-75E9B9FE42C2.webp'],    // aerial dusk lights
    ['HK', '20250831_114027(0).webp'],                        // double-decker canyon
  ],
  [
    ['HK', '20250829_204755.webp'],                           // neon harbour from the window
    ['HK', '20250830_144821.webp'],                           // promenade walkers
    ['City', '10DEA730-047C-41EF-AC1E-8A42A2A93EB7.webp'],    // b&w sea horizon
    ['HK', '20250829_173143.webp'],                           // street canyon, big sky
    ['City', '9A294631-CF05-4F6E-88A3-690947FD3450.webp'],    // night horizon from the plane
    ['HK', '20250831_114620.webp'],                           // canyon walls
    ['City', '19AE4761-D63F-4C4C-A77A-7DF33EBE8E25.webp'],    // night grid from the plane
  ],
]
const CITY_ROW_LEN = 12

const dimsByPath = new Map(manifest.photos.map(ph => [ph.path, ph]))

function toEntry(row) {
  const key = normalizePhotoKey(row.path, row.category, row.filename)
  const p = toPublicPath(key)
  const dims = dimsByPath.get(p)
  return {
    p,
    w: dims ? dims.w : null,
    h: dims ? dims.h : null,
    cat: row.category,
    createdAt: row.created_at ?? (dims ? dims.created_at : null),
    matte: dims ? !!dims.matte : false,
  }
}

async function fetchRows(db) {
  if (db) {
    try {
      const { results } = await db.prepare(
        'SELECT category, filename, path, sort_order, created_at FROM photos'
      ).all()
      if (results && results.length > 0) return results
    } catch (e) {
      console.error('darkroom: D1 query failed, falling back to manifest:', e.message)
    }
  }
  return manifest.photos
}

/** Round-robin interleave grouped lists so the wall mixes categories. */
function interleave(groups) {
  const out = []
  const lists = groups.filter(g => g.length > 0)
  const total = lists.reduce((s, l) => s + l.length, 0)
  let i = 0
  while (out.length < total) {
    for (const list of lists) {
      if (list[i]) out.push(list[i])
    }
    i++
  }
  return out
}

function buildPools(rows) {
  const pools = new Map()
  for (const row of rows) {
    const cat = typeof row.category === 'string' ? row.category.trim() : ''
    if (!cat) continue
    if (!pools.has(cat)) pools.set(cat, [])
    pools.get(cat).push(row)
  }
  for (const list of pools.values()) {
    list.sort((a, b) => {
      const sa = a.sort_order ?? Number.MAX_SAFE_INTEGER
      const sb = b.sort_order ?? Number.MAX_SAFE_INTEGER
      if (sa !== sb) return sa - sb
      return String(a.filename).localeCompare(String(b.filename))
    })
  }
  return pools
}

export async function getDarkroomHomeData(db) {
  const rows = await fetchRows(db)
  const pools = buildPools(rows)

  const findByName = (cat, filename) => {
    const row = (pools.get(cat) || []).find(r => r.filename === filename)
    return row ? toEntry(row) : null
  }

  const resolvePicks = picks => {
    const found = picks.map(([cat, f]) => findByName(cat, f)).filter(Boolean)
    return { found, missing: picks.length - found.length }
  }

  /** Top of a category pool, curated picks and white mattes excluded. */
  const takeClean = (cat, n, used) =>
    (pools.get(cat) || [])
      .map(toEntry)
      .filter(e => !e.matte && !(used && used.has(e.p)))
      .slice(0, n)

  const usedPaths = list => new Set(list.map(e => e.p))

  // ——— CH.01 PEOPLE — three auto-advancing film rows, Portrait only ———
  // One shared cursor into the uncurated remainder of the Portrait pool, so
  // the rows top themselves up without ever handing out the same frame twice.
  const portraitFill = (pools.get('Portrait') || [])
    .filter(r => !PEOPLE_CURATED.has(r.filename))
    .map(toEntry)
    .filter(e => !e.matte)
  let fillAt = 0

  const buildStrip = (picks, len) => {
    const row = resolvePicks(picks).found
    while (row.length < len && fillAt < portraitFill.length) row.push(portraitFill[fillAt++])
    return row
  }

  const stripA = buildStrip(STRIP_A_PICKS, PEOPLE_ROW_LEN[0])
  const stripB = buildStrip(STRIP_B_PICKS, PEOPLE_ROW_LEN[1])
  const stripC = buildStrip(STRIP_C_PICKS, PEOPLE_ROW_LEN[2])

  // ——— CH.02 CITY — three drifting layers ———
  // CITY uses shorter frames than PEOPLE, so each contact roll carries more
  // frames. Fill the hand-picked city/HK sequence without repeats.
  const cityFill = interleave([pools.get('City') || [], pools.get('HK') || []])
    .map(toEntry)
    .filter(e => !e.matte)
  // Reserve every curated pick before filling the first row, otherwise a
  // later row's intentional frame could be consumed as filler too early.
  const cityUsed = new Set(
    CITY_ROW_PICKS.flatMap(picks => resolvePicks(picks).found.map(entry => entry.p))
  )
  let cityAt = 0
  const takeCityFill = n => {
    const out = []
    while (out.length < n && cityAt < cityFill.length) {
      const next = cityFill[cityAt++]
      if (cityUsed.has(next.p)) continue
      cityUsed.add(next.p)
      out.push(next)
    }
    return out
  }
  const cityRows = CITY_ROW_PICKS.map(rowPicks => {
    const res = resolvePicks(rowPicks)
    const row = res.found
    row.push(...takeCityFill(CITY_ROW_LEN - row.length))
    return row
  })

  // ——— CH.03 WALL — a fixed 8 × 8 contact wall of white-matte squares ———
  // The wall is intentionally a single, balanced square rather than a pager.
  // Extra qualifying prints remain in the archive/category galleries.
  const WALL_SIDE = 8
  const mattesByCat = new Map()
  for (const ph of manifest.photos) {
    if (!ph.square || !ph.matte) continue
    if (!mattesByCat.has(ph.category)) mattesByCat.set(ph.category, [])
    mattesByCat.get(ph.category).push({ p: ph.path, w: ph.w, h: ph.h, cat: ph.category })
  }
  const wall = interleave([...mattesByCat.values()]).slice(0, WALL_SIDE * WALL_SIDE)

  // ——— INDEX overlay ———
  const knownOrder = CAT_ORDER.filter(c => pools.has(c))
  const extras = [...pools.keys()].filter(c => !CAT_ORDER.includes(c)).sort()
  const cats = [...knownOrder, ...extras].map(name => ({
    name,
    zh: CAT_ZH[name] || name,
    ja: CAT_JA[name] || name,
    count: (pools.get(name) || []).length,
    href: `/photographer/${name.toLowerCase()}`,
    thumbs: (pools.get(name) || []).slice(0, 4).map(r => toEntry(r).p),
  }))

  const counts = {
    total: rows.length,
    people: (pools.get('Portrait') || []).length,
    cats: cats.length,
    wall: wall.length,
  }

  return { hero: HERO_PANELS, stripA, stripB, stripC, cityRows, wall, cats, counts }
}

/**
 * Category gallery ("roll scan") data. Photos keep their native aspect
 * ratios and are chunked into justified rows (equal height per row via the
 * flex-grow = aspect-ratio trick), then grouped into film rolls.
 */
const ROW_TARGETS = [3.4, 4.3, 2.9, 3.8, 4.6, 3.1]
const ROLL_SIZES = [3, 4, 3, 4]
const LEAD_ROW_TARGET = 2.5
const LEAD_ROW_MAX = 4

/** First row of a gallery: a few big prints filling the full row width,
 *  instead of one lonely lead card that rarely spans the space on its own. */
function takeLeadRow(entries) {
  const items = []
  let sum = 0
  for (const e of entries) {
    const ar = e.w && e.h ? e.w / e.h : 1.5
    items.push({ ...e, ar: Math.round(ar * 1000) / 1000 })
    sum += ar
    if (sum >= LEAD_ROW_TARGET || items.length >= LEAD_ROW_MAX) break
  }
  return { items, target: Math.max(sum, LEAD_ROW_TARGET), partial: false }
}

function chunkJustified(entries) {
  const rows = []
  let items = []
  let sum = 0
  let ti = 0
  for (const e of entries) {
    const ar = e.w && e.h ? e.w / e.h : 1.5
    items.push({ ...e, ar: Math.round(ar * 1000) / 1000 })
    sum += ar
    if (sum >= ROW_TARGETS[ti % ROW_TARGETS.length] || items.length >= 5) {
      rows.push({ items, target: sum, partial: false })
      items = []
      sum = 0
      ti++
    }
  }
  if (items.length) {
    // Don't stretch a thin trailing row to full width — pad with a spacer.
    const target = ROW_TARGETS[ti % ROW_TARGETS.length]
    rows.push({ items, target: Math.max(sum, Math.min(target, sum * 1.9)), partial: sum < target * 0.72 })
  }
  return rows
}

export async function getDarkroomGalleryData(db, slug) {
  const rows = await fetchRows(db)
  const pools = buildPools(rows)

  const name = [...pools.keys()].find(c => c.toLowerCase() === String(slug).toLowerCase())
  if (!name) return null

  // Portrait remains a deliberately curated sequence. Every other category is
  // an archive: newest captures belong at the top of its detail page, with a
  // deterministic filename tie-breaker for photos imported at the same time.
  const galleryRows = name === 'Portrait'
    ? pools.get(name)
    : [...pools.get(name)].sort((a, b) => {
      const timeDiff = Number(b.created_at || 0) - Number(a.created_at || 0)
      if (timeDiff) return timeDiff
      return String(b.filename || '').localeCompare(String(a.filename || ''))
    })
  const entries = galleryRows.map((r, i) => ({ ...toEntry(r), n: i + 1 }))
  const leadRow = entries.length ? takeLeadRow(entries) : null
  const justified = chunkJustified(entries.slice(leadRow ? leadRow.items.length : 0))

  const rolls = []
  let ri = 0
  let cursor = 0
  while (cursor < justified.length) {
    const take = ROLL_SIZES[ri % ROLL_SIZES.length]
    rolls.push(justified.slice(cursor, cursor + take))
    cursor += take
    ri++
  }

  const knownOrder = CAT_ORDER.filter(c => pools.has(c))
  const extras = [...pools.keys()].filter(c => !CAT_ORDER.includes(c)).sort()
  const orderedCats = [...knownOrder, ...extras]
  const idx = orderedCats.indexOf(name)
  const catInfo = c => ({
    name: c,
    zh: CAT_ZH[c] || c,
    ja: CAT_JA[c] || c,
    count: (pools.get(c) || []).length,
    href: `/photographer/${c.toLowerCase()}`,
  })

  return {
    name,
    zh: CAT_ZH[name] || name,
    ja: CAT_JA[name] || name,
    count: entries.length,
    leadRow,
    rolls,
    cats: orderedCats.map(catInfo),
    prev: catInfo(orderedCats[(idx - 1 + orderedCats.length) % orderedCats.length]),
    next: catInfo(orderedCats[(idx + 1) % orderedCats.length]),
  }
}
